def compute_score(reward_inputs: List[Dict[str, Any]], format_weight: float = 0.1, alpha_length_bonus: float = 0.5, alpha_entropy: float = 0.5) -> List[Dict[str, float]]:
    import math
    from typing import List, Dict, Any

    def huber_loss(x, kappa):
        if abs(x) <= kappa:
            return 0.5 * x ** 2
        else:
            return kappa * (abs(x) - 0.5 * kappa)

    def sigmoid(x, temp):
        return 1 / (1 + math.exp(-x / temp))

    def get_params(difficulty):
        if difficulty == "easy":
            return 0.15, 2.0, 2.0, 1.0
        elif difficulty == "medium":
            return 0.25, 3.0, 2.5, 1.0
        elif difficulty == "hard":
            return 0.35, 4.0, 3.0, 1.2
        else:
            return 0.25, 3.0,293.0, 1.0

    scores = []
    for inp in reward_inputs:
        response = inp.get("response", "")
        ground_truth = inp.get("ground_truth", "")
        difficulty = inp.get("difficulty", "medium")
        high_entropy_token_num = inp.get("high_entropy_token_num", 0)
        target_high_entropy_token_num = inp.get("target_high_entropy_token_num", 0)
        alpha_entropy_sample = inp.get("alpha_entropy", alpha_entropy)
        accuracy = inp.get("accuracy")
        if accuracy is None:
            accuracy = 1.0 if response.strip() == ground_truth.strip() else 0.0
        format_score = 1.0 if response.strip() else 0.0
        format_score *= format_weight
        margin_frac, kappa, temp, cap_scale = get_params(difficulty)
        target = target_high_entropy_token_num
        actual = high_entropy_token_num
        if target == 0:
            rel_diff = 0.0
        else:
            rel_diff = (actual - target) / (target + 1e-8)
        margin = margin_frac * target
        if difficulty == "easy":
            if accuracy == 1.0:
                if actual > target + margin:
                    penalty = huber_loss(actual - target - margin, kappa)
                    entropy_reward = -penalty
                else:
                    entropy_reward = 0.0
            else:
                entropy_reward = sigmoid(actual - target, temp) * cap_scale
        elif difficulty == "medium":
            if accuracy == 1.0:
                if abs(actual - target) > margin:
                    penalty = huber_loss(abs(actual - target) - margin, kappa)
                    entropy_reward = -penalty
                else:
                    entropy_reward = 0.0
            else:
                entropy_reward = sigmoid(actual - target, temp) * cap_scale
        elif difficulty == "hard":
            if accuracy == 1.0:
                if actual < target - margin:
                    penalty = huber_loss(target - margin - actual, kappa)
                    entropy_reward = -penalty
                else:
                    entropy_reward = sigmoid(actual - target, temp) * cap_scale
            else:
                entropy_reward = sigmoid(actual - target, temp) * cap_scale
        else:
            entropy_reward = 0.0
        entropy_score = alpha_entropy_sample * entropy_reward
        overall = accuracy + format_score + entropy_score
        scores.append({
            "overall": overall,
            "accuracy": accuracy,
            "format": format_score,
            "high_entropy_token_num_score": entropy_score
        })
    return scores

